CREATE TABLE assessment_types_to_policies
(
	id serial,
	assessment_type_id integer NOT NULL,
	policy_id integer DEFAULT NULL,
	CONSTRAINT pk_assessment_types_to_policies PRIMARY KEY (id)
	, CONSTRAINT fk_assessment_types_to_policies_to_assessment_types FOREIGN KEY (assessment_type_id) REFERENCES assessment_types (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_assessment_types_to_policies_to_policies FOREIGN KEY (policy_id) REFERENCES policies (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_assessment_types_to_policies_assessment_type ON assessment_types_to_policies (assessment_type_id);
CREATE INDEX i_assessment_types_to_policies_policy ON assessment_types_to_policies (policy_id);


CREATE TABLE gdpr_articles_to_policies
(
	id serial,
	gdpr_article_id integer NOT NULL,
	policy_id integer DEFAULT NULL,
	CONSTRAINT pk_gdpr_articles_to_policies PRIMARY KEY (id)
	, CONSTRAINT fk_gdpr_articles_to_policies_to_gdpr_article FOREIGN KEY (gdpr_article_id) REFERENCES gdpr_article (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_gdpr_articles_to_policies_to_policies FOREIGN KEY (policy_id) REFERENCES policies (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_gdpr_articles_to_policies_gdpr_article ON gdpr_articles_to_policies (gdpr_article_id);
CREATE INDEX i_gdpr_articles_to_policies_policy ON gdpr_articles_to_policies (policy_id);
